            var options = new JwtAuthenticationOptions();
            configureOptions?.Invoke(options);

            var configuration = builder.ApplicationServices.GetRequiredService<IConfiguration>();

            if (string.IsNullOrWhiteSpace(options.ValidIssuer))
            {
                options.ValidIssuer = configuration["Jwt:Issuer"]
                    ?? throw new InvalidOperationException("JWT Issuer must be configured via 'Jwt:Issuer' or provided in options.");
            }

            if (string.IsNullOrWhiteSpace(options.ValidAudience))
            {
                options.ValidAudience = configuration["Jwt:Audience"]
                    ?? throw new InvalidOperationException("JWT Audience must be configured via 'Jwt:Audience' or provided in options.");
            }

            return builder.UseMiddleware<JwtAuthenticationMiddleware>(configuration, options);
        }
    }

    public class RequireAuthenticationMiddleware
    {
        private readonly RequestDelegate _next;
