    public static class JwtTokenGenerator
    {
        public static string GenerateToken(
            IConfiguration configuration,
            IEnumerable<Claim> claims,
            TimeSpan? expiration = null)
        {
            var signingKeyValue = configuration["Jwt:SigningKey"];
            if (string.IsNullOrWhiteSpace(signingKeyValue))
                throw new InvalidOperationException("JWT signing key is not configured.");

            var issuer = configuration["Jwt:Issuer"];
            var audience = configuration["Jwt:Audience"];

            if (string.IsNullOrWhiteSpace(issuer))
                throw new InvalidOperationException("JWT issuer is not configured.");
            if (string.IsNullOrWhiteSpace(audience))
                throw new InvalidOperationException("JWT audience is not configured.");

            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(signingKeyValue));
            var credentials = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var effectiveExpiration = expiration ?? TimeSpan.FromHours(1);

            if (effectiveExpiration > TimeSpan.FromHours(24))
            {
                throw new ArgumentException(
                    "Token expiration should not exceed 24 hours. Use refresh tokens for longer sessions.");
            }

            var allClaims = new List<Claim>(claims)
            {
                new Claim(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString()),
                new Claim(JwtRegisteredClaimNames.Iat,
                    DateTimeOffset.UtcNow.ToUnixTimeSeconds().ToString(),
                    ClaimValueTypes.Integer64)
            };

            var tokenDescriptor = new SecurityTokenDescriptor
            {
                Subject = new ClaimsIdentity(allClaims),
                Expires = DateTime.UtcNow.Add(effectiveExpiration),
                NotBefore = DateTime.UtcNow,
                Issuer = issuer,
                Audience = audience,
                SigningCredentials = credentials
            };

            var tokenHandler = new JwtSecurityTokenHandler();
            var token = tokenHandler.CreateToken(tokenDescriptor);
            return tokenHandler.WriteToken(token);
        }
